import os

class MalwareDetector:
    def __init__(self):
        self.rules = {
            'rule1': {'pattern': 'pattern1', 'severity': 'high'},
            'rule2': {'pattern': 'pattern2', 'severity': 'medium'},
            'rule3': {'pattern': 'pattern3', 'severity': 'low'}
        }

    def scan_file(self, file_path):
        for rule in self.rules.values():
