                return f"Malware detected! Severity: {rule['severity']}"

        return "No malware detected"

    def match_pattern(self, file_path, pattern):
        try:
            with open(file_path, 'r') as file:
                content = file.read()
                return pattern in content
        except FileNotFoundError:
            return False

